PreToolUse.command:
# Block edits to protected files
case "$FILEPATH" in
  */.env|*/.env.*) echo 'BLOCKED: .env files are protected' && exit 1 ;;
  */.git/*) echo 'BLOCKED: .git/ is protected' && exit 1 ;;
  */.specify/constitution.md) echo 'BLOCKED: constitution.md is protected — use /compass-edit' && exit 1 ;;
esac
